// swift-tools-version:6.0
import PackageDescription

let package = Package(
    name: "OpenRouterFusion",
    platforms: [.macOS(.v14)],
    products: [
        .executable(name: "OpenRouterFusion", targets: ["OpenRouterFusion"])
    ],
    dependencies: [],
    targets: [
        .executableTarget(
            name: "OpenRouterFusion",
            dependencies: [],
            resources: [.process("Resources")]
        )
    ],
    swiftLanguageModes: [.v5]
)

import SwiftUI

@main
struct OpenRouterFusionApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
                .frame(minWidth: 800, minHeight: 500)
        }
        .windowStyle(.hiddenTitleBar)
        .defaultSize(width: 1100, height: 700)
        .commands {
            // Replace the default File menu with our clear command
            CommandGroup(after: .newItem) {
                Divider()
                Button("Clear Chat") {
                    NotificationCenter.default.post(name: .clearChat, object: nil)
                }
                .keyboardShortcut("k", modifiers: .command)

                Button("Toggle Sidebar") {
                    NotificationCenter.default.post(name: .toggleSidebar, object: nil)
                }
                .keyboardShortcut("s", modifiers: [.command, .shift])
            }
        }
    }
}

extension Notification.Name {
    static let clearChat = Notification.Name("clearChat")
    static let toggleSidebar = Notification.Name("toggleSidebar")
}

import SwiftUI

// MARK: - Model display name helper

private func friendlyModelName(_ id: String) -> String {
    // Strip common prefixes/suffixes
    var name = id
        .replacingOccurrences(of: "openrouter/", with: "")
        .replacingOccurrences(of: "openai/", with: "")
        .replacingOccurrences(of: "google/", with: "")
        .replacingOccurrences(of: "nvidia/", with: "")
        .replacingOccurrences(of: "qwen/", with: "")
        .replacingOccurrences(of: "nex-agi/", with: "")
        .replacingOccurrences(of: "anthropic/", with: "")
        .replacingOccurrences(of: ":free", with: "")
        .replacingOccurrences(of: "-instruct", with: "")
        .replacingOccurrences(of: "-it", with: "")

    // Convert dashes/spaces to title case
    name = name.replacingOccurrences(of: "-", with: " ")
    name = name.capitalized

    // Truncate if still long
    if name.count > 28 {
        name = String(name.prefix(25)) + "…"
    }
    return name
}

// MARK: - ContentView

struct ContentView: View {
    @StateObject private var store = ConversationStore()
    @StateObject private var router = RouterManager()

    @State private var userInput = ""
    @State private var systemPrompt = ""
    @State private var isStreaming = false
    @State private var selectedModel = ""
    @State private var currentStreamingContent = ""
    @State private var showingToolModal = false
    @State private var toolCommand = ""
    @State private var activeToolCalls: [ToolCallDisplay] = []
    @State private var sidebarVisible = true
    @State private var showingKeychainAlert = false
    @State private var keychainAlertMessage = ""

    var body: some View {
        HStack(spacing: 0) {
            if sidebarVisible {
                sidebar
                Divider().background(Color.lrmBorder)
            }
            chatArea
        }
        .background(
            ZStack {
                Color.lrmBackground
                LinearGradient.lrmBackgroundRadial.opacity(0.4)
            }
            .ignoresSafeArea()
        )
        .alert("Keychain Error", isPresented: $showingKeychainAlert) {
            Button("OK", role: .cancel) {}
        } message: {
            Text(keychainAlertMessage)
        }
        .sheet(isPresented: $showingToolModal) {
            ToolModalView(command: $toolCommand, onRun: runManualTool)
        }
        .onAppear {
            if let saved = UserDefaults.standard.string(forKey: "systemPrompt") {
                systemPrompt = saved
            } else {
                systemPrompt = "You are a helpful AI assistant running on a macOS machine. Your home directory is \(NSHomeDirectory())."
            }
            selectedModel = router.config.default

            if KeychainHelper.shared.get(key: "OpenRouterAPIKey") == nil,
               let apiKey = UserDefaults.standard.string(forKey: "openrouter_api_key"), !apiKey.isEmpty {
                let ok = KeychainHelper.shared.set(apiKey, for: "OpenRouterAPIKey")
                if !ok {
                    keychainAlertMessage = "Could not save API key to Keychain. It will only persist for this session."
                    showingKeychainAlert = true
                }
            }
        }
        .onChange(of: systemPrompt) {
            UserDefaults.standard.set(systemPrompt, forKey: "systemPrompt")
        }
    }

    // MARK: - Sidebar

    private var sidebar: some View {
        VStack(alignment: .leading, spacing: 12) {
            // Sidebar header with collapse button
            HStack {
                MetalText("SETTINGS")
                Spacer()
                Button(action: { withAnimation(.easeInOut(duration: 0.2)) { sidebarVisible = false } }) {
                    Image(systemName: "sidebar.left")
                        .font(.system(size: 12, weight: .semibold))
                        .foregroundColor(.lrmMuted)
                        .padding(6)
                }
                .buttonStyle(PlainButtonStyle())
                .help("Hide sidebar")
            }
            .padding(.bottom, 4)

            // API Key
            MetalText("API KEY")
            LRMSecureField(text: Binding(
                get: { KeychainHelper.shared.get(key: "OpenRouterAPIKey") ?? "" },
                set: { newValue in
                    let ok = KeychainHelper.shared.set(newValue, for: "OpenRouterAPIKey")
                    if !ok && !newValue.isEmpty {
                        keychainAlertMessage = "Failed to save API key to Keychain."
                        showingKeychainAlert = true
                    }
                }
            ))
            .frame(height: 28)

            // System Prompt
            MetalText("SYSTEM PROMPT")
            LRMTextEditor(text: $systemPrompt, placeholder: "You are a helpful assistant…")
                .frame(minHeight: 60, maxHeight: 100)

            // Model Picker
            MetalText("MODEL")
            Picker("Model", selection: $selectedModel) {
                Text("Auto (\(friendlyModelName(router.config.default)))").tag("")
                ForEach(router.config.fallbackOrder, id: \.self) { model in
                    Text(friendlyModelName(model)).tag(model)
                }
            }
            .pickerStyle(.menu)
            .accentColor(.lrmAccent)

            MetalButton("Run Tool…", variant: .metal) {
                showingToolModal = true
            }

            Spacer()

            MetalButton("Clear Chat", variant: .ghost) {
                store.clear()
                activeToolCalls = []
            }
        }
        .padding(14)
        .frame(width: 260)
        .background(Color.lrmBackground2.opacity(0.6))
    }

    // MARK: - Chat Area

    private var chatArea: some View {
        VStack(spacing: 0) {
            // Show sidebar toggle when sidebar is hidden
            if !sidebarVisible {
                HStack {
                    Button(action: { withAnimation(.easeInOut(duration: 0.2)) { sidebarVisible = true } }) {
                        Image(systemName: "sidebar.left")
                            .font(.system(size: 12, weight: .semibold))
                            .foregroundColor(.lrmMuted)
                            .padding(8)
                    }
                    .buttonStyle(PlainButtonStyle())
                    .help("Show sidebar")
                    Spacer()
                }
                .padding(.horizontal, 12)
                .padding(.vertical, 6)
                .background(Color.lrmBackground2.opacity(0.3))
            }

            if store.messages.isEmpty && !isStreaming {
                emptyState
            } else {
                chatLog
            }

            Divider().background(Color.lrmBorder)
            composer
        }
    }

    // MARK: - Empty State

    private var emptyState: some View {
        VStack(spacing: 20) {
            Spacer()

            // Logo
            Text("◉")
                .font(.system(size: 48, weight: .thin))
                .foregroundColor(.lrmAccent)

            VStack(spacing: 6) {
                Text("OpenRouterFusion")
                    .font(.system(size: 22, weight: .black, design: .rounded))
                    .foregroundColor(.lrmTextStrong)

                Text("Multi-model AI chat · auto-routing · free models")
                    .font(.system(size: 13, weight: .medium))
                    .foregroundColor(.lrmMuted)
            }

            VStack(spacing: 8) {
                Text("Quick start:")
                    .font(.system(size: 11, weight: .semibold))
                    .foregroundColor(.lrmMuted.opacity(0.7))

                VStack(alignment: .leading, spacing: 4) {
                    quickStartRow(key: "Enter", action: "Send message")
                    quickStartRow(key: "⇧ Enter", action: "New line")
                    quickStartRow(key: "⌘ K", action: "Clear chat")
                    quickStartRow(key: "⌘ ⇧ S", action: "Toggle sidebar")
                }
            }
            .padding(.top, 12)

            Spacer()
        }
        .frame(maxWidth: .infinity)
    }

    private func quickStartRow(key: String, action: String) -> some View {
        HStack(spacing: 12) {
            Text(key)
                .font(.system(size: 11, weight: .bold, design: .monospaced))
                .foregroundColor(.lrmAccent)
                .frame(width: 80, alignment: .trailing)
            Text(action)
                .font(.system(size: 12))
                .foregroundColor(.lrmMuted)
        }
    }

    // MARK: - Chat Log

    private var chatLog: some View {
        ScrollViewReader { proxy in
            ScrollView {
                LazyVStack(alignment: .leading, spacing: 12) {
                    ForEach(store.messages) { msg in
                        ChatMessageView(message: msg)
                            .id(msg.id)
                    }

                    ForEach(activeToolCalls) { tc in
                        ToolCallIndicator(toolCall: tc)
                            .id("tool-\(tc.id)")
                    }

                    if isStreaming {
                        ChatMessageView(
                            message: ChatMessage(role: .assistant, content: currentStreamingContent)
                        )
                        .id("streaming")
                    }
                }
                .padding(.vertical, 20)
                .frame(maxWidth: .infinity)
            }
            .onChange(of: store.messages.count) {
                withAnimation(.easeOut(duration: 0.2)) {
                    if let last = store.messages.last {
                        proxy.scrollTo(last.id, anchor: .bottom)
                    }
                }
            }
            .onChange(of: currentStreamingContent) {
                withAnimation(.easeOut(duration: 0.1)) {
                    proxy.scrollTo("streaming", anchor: .bottom)
                }
            }
            .onChange(of: activeToolCalls.count) {
                withAnimation(.easeOut(duration: 0.2)) {
                    if let last = activeToolCalls.last {
                        proxy.scrollTo("tool-\(last.id)", anchor: .bottom)
                    }
                }
            }
        }
    }

    // MARK: - Composer

    private var composer: some View {
        HStack(alignment: .bottom, spacing: 10) {
            ZStack(alignment: .topLeading) {
                if userInput.isEmpty {
                    Text("Message…")
                        .foregroundColor(.lrmMuted.opacity(0.5))
                        .padding(.horizontal, 8)
                        .padding(.vertical, 6)
                        .allowsHitTesting(false)
                }
                TextEditor(text: $userInput)
                    .font(.system(size: 14))
                    .foregroundColor(.lrmText)
                    .scrollContentBackground(.hidden)
                    .background(Color.clear)
                    .padding(.horizontal, 4)
                    .padding(.vertical, 2)
                    .frame(minHeight: 36, maxHeight: 120)
                    .onSubmit { sendMessage() }
            }
            .background(
                Color.lrmSurfaceStrong.clipShape(ChamferShape(cornerSize: 8))
            )
            .overlay(
                ChamferShape(cornerSize: 8).stroke(Color.lrmBorder, lineWidth: 1)
            )

            HStack(spacing: 8) {
                if isStreaming {
                    MetalButton("Stop", variant: .ghost) {
                        isStreaming = false
                        if !currentStreamingContent.isEmpty {
                            store.append(role: .assistant, content: currentStreamingContent)
                            currentStreamingContent = ""
                        }
                        activeToolCalls = []
                    }
                } else {
                    MetalButton("Send", variant: .primary) {
                        sendMessage()
                    }
                    .disabled(userInput.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                    .keyboardShortcut(.return, modifiers: [])
                }
            }
        }
        .padding(12)
        .background(Color.lrmSurface.opacity(0.3))
    }

    // MARK: - Messaging

    private func sendMessage() {
        let prompt = userInput.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !prompt.isEmpty else { return }

        store.append(role: .user, content: prompt, modelUsed: nil)
        userInput = ""
        isStreaming = true
        currentStreamingContent = ""
        activeToolCalls = []

        let messagesArray = store.messages.map { msg in
            ["role": msg.role.rawValue, "content": msg.content]
        }
        let sysPrompt = systemPrompt.isEmpty ? nil : systemPrompt
        let tools: [[String: Any]]? = nil  // No tool calling for now

        router.send(
            messages: messagesArray,
            systemPrompt: sysPrompt,
            tools: tools,
            onChunk: { chunk in
                DispatchQueue.main.async {
                    currentStreamingContent += chunk
                }
            },
            onToolCall: { id, name, args in
                DispatchQueue.main.async {
                    if !activeToolCalls.contains(where: { $0.id == id }) {
                        activeToolCalls.append(ToolCallDisplay(id: id, name: name, arguments: args))
                    }
                    executeTool(id: id, name: name, arguments: args)
                }
            },
            completion: { result in
                DispatchQueue.main.async {
                    isStreaming = false
                    switch result {
                    case .success(let txt):
                        let finalText = txt.isEmpty ? currentStreamingContent : txt
                        if !finalText.isEmpty {
                            store.append(role: .assistant, content: finalText)
                        }
                    case .failure(let err):
                        store.append(role: .assistant, content: "❗️ Error: \(err.localizedDescription)")
                    }
                    currentStreamingContent = ""
                    activeToolCalls = []
                }
            }
        )
    }

    private func executeTool(id: String, name: String, arguments argsJSON: String) {
        ToolExecutor.run("/bin/bash", arguments: ["-c", argsJSON]) { result in
            DispatchQueue.main.async {
                switch result {
                case .success(let output):
                    let truncated = output.count > 2000 ? String(output.prefix(2000)) + "\n…(truncated)" : output
                    store.append(role: .assistant, content: "🛠 [\(name)] → \(truncated)")
                case .failure(let err):
                    store.append(role: .assistant, content: "🛠 [\(name)] failed: \(err.localizedDescription)")
                }
            }
        }
    }

    private func runManualTool(_ cmd: String) {
        ToolExecutor.run("/bin/bash", arguments: ["-c", cmd]) { result in
            DispatchQueue.main.async {
                switch result {
                case .success(let out):
                    store.append(role: .assistant, content: """
                    🛠 Tool output:
                    ```
                    \(out)
                    ```
                    """)
                case .failure(let err):
                    store.append(role: .assistant, content: "🛠 Tool failed: \(err.localizedDescription)")
                }
            }
        }
    }
}

// MARK: - Keyboard Shortcuts

extension ContentView {
    func clearChatShortcut() {
        store.clear()
        activeToolCalls = []
    }
}

// MARK: - Tool Call Display

struct ToolCallDisplay: Identifiable {
    let id: String
    let name: String
    let arguments: String
}

struct ToolCallIndicator: View {
    let toolCall: ToolCallDisplay

    var body: some View {
        HStack(spacing: 8) {
            Image(systemName: "gearshape.fill")
                .foregroundColor(.lrmAccent)
                .font(.system(size: 12))
            Text(toolCall.name)
                .font(.system(size: 12, weight: .semibold, design: .monospaced))
                .foregroundColor(.lrmTextStrong)
            Text(summary)
                .font(.system(size: 11, design: .monospaced))
                .foregroundColor(.lrmMuted)
                .lineLimit(1)
            Spacer()
            PulsingDots()
                .frame(width: 16, height: 6)
        }
        .padding(.horizontal, 14)
        .padding(.vertical, 8)
        .background(Color.lrmSurface.clipShape(ChamferShape(cornerSize: 6)))
        .overlay(ChamferShape(cornerSize: 6).stroke(Color.lrmAccent.opacity(0.3), lineWidth: 1))
        .clipShape(ChamferShape(cornerSize: 6))
        .padding(.horizontal, 16)
    }

    private var summary: String {
        let cleaned = toolCall.arguments.replacingOccurrences(of: "\n", with: " ")
        return cleaned.count > 60 ? String(cleaned.prefix(60)) + "…" : cleaned
    }
}

import Foundation

struct ChatMessage: Identifiable, Codable {
    var id = UUID()
    var role: Role
    var content: String
    var modelUsed: String?
    enum Role: String, Codable { case user, assistant }
}

final class ConversationStore: ObservableObject {
    @Published var messages: [ChatMessage] = []

    private let fileURL: URL = {
        let support = FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask)[0]
        let folder = support.appendingPathComponent("OpenRouterFusion")
        try? FileManager.default.createDirectory(at: folder, withIntermediateDirectories: true)
        return folder.appendingPathComponent("conversation.json")
    }()

    init() { load() }

    private func load() {
        guard let data = try? Data(contentsOf: fileURL) else { return }
        guard let decoded = try? JSONDecoder().decode([ChatMessage].self, from: data) else {
            // Corrupted file — back it up and start fresh
            let backup = fileURL.appendingPathExtension("bak")
            try? FileManager.default.moveItem(at: fileURL, to: backup)
            print("⚠️ conversation.json was corrupted, backed up to \(backup.lastPathComponent)")
            return
        }
        messages = decoded
    }

    func save() {
        guard let data = try? JSONEncoder().encode(messages) else { return }
        try? data.write(to: fileURL, options: .atomic)
    }

    func append(role: ChatMessage.Role, content: String, modelUsed: String? = nil) {
        messages.append(ChatMessage(role: role, content: content, modelUsed: modelUsed))
        save()
    }

    func clear() {
        messages.removeAll()
        save()
    }
}

import Foundation
import Security

final class KeychainHelper {
    static let shared = KeychainHelper()
    private init() {}
    func set(_ value: String, for key: String) -> Bool {
        let data = Data(value.utf8)
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlock
        ]
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    func get(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        guard status == errSecSuccess, let data = result as? Data, let str = String(data: data, encoding: .utf8) else { return nil }
        return str
    }
    func delete(key: String) {
        let query: [String: Any] = [kSecClass as String: kSecClassGenericPassword,
                                    kSecAttrAccount as String: key]
        SecItemDelete(query as CFDictionary)
    }
}

import Foundation

final class RouterManager: ObservableObject {
    struct Config: Decodable {
        let `default`: String
        let fallbackOrder: [String]
        let maxRetries: Int
        let timeoutSeconds: Int
    }

    enum RouterError: LocalizedError {
        case configNotFound(String)
        case configDecodeFailed(Error)
        case serializationFailed(Error)
        case invalidResponse
        case httpError(Int)
        case apiKeyMissing
        case allModelsExhausted

        var errorDescription: String? {
            switch self {
            case .configNotFound(let paths):
                return "ModelConfig.json not found. Searched: \(paths)"
            case .configDecodeFailed(let err):
                return "Failed to decode ModelConfig.json: \(err.localizedDescription)"
            case .serializationFailed(let err):
                return "Failed to serialize request body: \(err.localizedDescription)"
            case .invalidResponse:
                return "Invalid response from server"
            case .httpError(let code):
                return "HTTP \(code)"
            case .apiKeyMissing:
                return "OpenRouter API key missing"
            case .allModelsExhausted:
                return "All models exhausted"
            }
        }
    }

    let config: Config
    @Published var modelUsed: String = ""
    private let apiKeyKey = "OpenRouterAPIKey"

    init() throws {
        // Search multiple locations for ModelConfig.json (bundle app vs swift package)
        let candidates = [
            Bundle.main.url(forResource: "ModelConfig", withExtension: "json"),
            Bundle.main.url(forResource: "ModelConfig", withExtension: "json", subdirectory: "Resources"),
            Bundle.main.resourceURL?.appendingPathComponent("ModelConfig.json"),
            Bundle.main.resourceURL?.appendingPathComponent("Resources/ModelConfig.json"),
        ]
        let searchedPaths = candidates.compactMap { $0?.path }
        guard let url = candidates.compactMap({ $0 }).first else {
            throw RouterError.configNotFound(searchedPaths.joined(separator: ", "))
        }
        guard let data = try? Data(contentsOf: url) else {
            throw RouterError.configNotFound("Could not read data from \(url.path)")
        }
        do {
            config = try JSONDecoder().decode(Config.self, from: data)
        } catch {
            throw RouterError.configDecodeFailed(error)
        }
    }

    // MARK: - Send with streaming + optional tool calling

    func send(
        messages: [[String: Any]],
        systemPrompt: String?,
        tools: [[String: Any]]?,
        onChunk: @escaping (String) -> Void,
        onToolCall: @escaping (String, String, String) -> Void,
        completion: @escaping (Result<String, Error>) -> Void
    ) {
        let candidates = [config.default] + config.fallbackOrder
        var attempt = 0
        var lastError: Error?

        func tryNext() {
            guard attempt < candidates.count && attempt < config.maxRetries else {
                completion(.failure(lastError ?? RouterError.allModelsExhausted))
                return
            }
            let model = candidates[attempt]
            attempt += 1

            streamRequest(
                model: model, messages: messages,
                systemPrompt: systemPrompt, tools: tools,
                onChunk: onChunk, onToolCall: onToolCall
            ) { [weak self] result in
                switch result {
                case .success(let txt):
                    self?.modelUsed = model
                    completion(.success(txt))
                case .failure(let err):
                    print("⚠️ Model \(model) failed: \(err.localizedDescription); retrying…")
                    lastError = err
                    tryNext()
                }
            }
        }

        tryNext()
    }

    // MARK: - True SSE streaming via URLSession.bytes(for:)

    private func streamRequest(
        model: String,
        messages: [[String: Any]],
        systemPrompt: String?,
        tools: [[String: Any]]?,
        onChunk: @escaping (String) -> Void,
        onToolCall: @escaping (String, String, String) -> Void,
        completion: @escaping (Result<String, Error>) -> Void
    ) {
        guard let apiKey = KeychainHelper.shared.get(key: apiKeyKey), !apiKey.isEmpty else {
            completion(.failure(RouterError.apiKeyMissing))
            return
        }

        var body: [String: Any] = [
            "model": model,
            "messages": messages,
            "stream": true
        ]
        if let sys = systemPrompt { body["system"] = sys }
        if let tools = tools { body["tools"] = tools }

        guard let endpoint = URL(string: "https://openrouter.ai/api/v1/chat/completions") else {
            completion(.failure(RouterError.invalidResponse))
            return
        }
        var request = URLRequest(url: endpoint)
        request.httpMethod = "POST"
        request.timeoutInterval = TimeInterval(config.timeoutSeconds)
        request.addValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization")
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: body)
        } catch {
            completion(.failure(RouterError.serializationFailed(error)))
            return
        }

        let session = URLSession(configuration: .default)
        var accumulated = ""
        var toolCalls: [Int: [String: Any]] = [:]
        var completed = false
        let lock = NSLock()

        /// Thread-safe single-fire completion helper
        func safeComplete(_ result: Result<String, Error>) {
            lock.lock()
            defer { lock.unlock() }
            guard !completed else { return }
            completed = true
            Task { @MainActor in
                completion(result)
            }
        }

        /// Fire accumulated tool calls on MainActor
        @MainActor
        func fireToolCalls() {
            for (_, tc) in toolCalls.sorted(by: { $0.key < $1.key }) {
                if let id = tc["id"] as? String,
                   let name = tc["name"] as? String,
                   let args = tc["arguments"] as? String {
                    onToolCall(id, name, args)
                }
            }
        }

        Task {
            do {
                let (bytes, response) = try await session.bytes(for: request)

                guard let httpResp = response as? HTTPURLResponse else {
                    throw RouterError.invalidResponse
                }
                guard 200..<300 ~= httpResp.statusCode else {
                    throw RouterError.httpError(httpResp.statusCode)
                }

                var dataBuffer = Data()

                for try await byte in bytes {
                    dataBuffer.append(byte)

                    // Process complete lines
                    while let newlineIdx = dataBuffer.firstIndex(of: 0x0A) {
                        let lineData = dataBuffer.subdata(in: dataBuffer.startIndex..<newlineIdx)
                        let remainingStart = dataBuffer.index(after: newlineIdx)
                        dataBuffer = remainingStart < dataBuffer.endIndex
                            ? dataBuffer.subdata(in: remainingStart..<dataBuffer.endIndex)
                            : Data()

                        guard let line = String(data: lineData, encoding: .utf8)?.trimmingCharacters(in: .whitespaces)
                        else { continue }
                        if !line.hasPrefix("data: ") { continue }

                        let jsonStr = String(line.dropFirst(6))
                        if jsonStr == "[DONE]" {
                            safeComplete(.success(accumulated))
                            return
                        }

                        guard let jsonData = jsonStr.data(using: .utf8) else { continue }
                        guard let json = try? JSONSerialization.jsonObject(with: jsonData) as? [String: Any] else { continue }
                        guard let choices = json["choices"] as? [[String: Any]] else { continue }
                        guard let delta = choices.first?["delta"] as? [String: Any] else { continue }

                        // Text content — fire onChunk immediately for each token
                        if let content = delta["content"] as? String, !content.isEmpty {
                            accumulated += content
                            await MainActor.run {
                                onChunk(content)
                            }
                        }

                        // Tool calls (streamed incrementally)
                        if let deltaTools = delta["tool_calls"] as? [[String: Any]] {
                            for deltaTool in deltaTools {
                                let index = deltaTool["index"] as? Int ?? 0
                                if toolCalls[index] == nil {
                                    toolCalls[index] = [:]
                                }
                                if let id = deltaTool["id"] as? String {
                                    toolCalls[index]!["id"] = id
                                }
                                if let function = deltaTool["function"] as? [String: Any] {
                                    if let name = function["name"] as? String {
                                        toolCalls[index]!["name"] = name
                                    }
                                    if let args = function["arguments"] as? String {
                                        let existing = toolCalls[index]!["arguments"] as? String ?? ""
                                        toolCalls[index]!["arguments"] = existing + args
                                    }
                                }
                            }
                        }

                        // Check for finish_reason
                        if let finishReason = choices.first?["finish_reason"] as? String,
                           finishReason == "stop" || finishReason == "length" {
                            await fireToolCalls()
                            safeComplete(.success(accumulated))
                            return
                        }
                    }
                }

                // Stream ended without [DONE]
                await fireToolCalls()
                safeComplete(.success(accumulated))

            } catch {
                safeComplete(.failure(error))
            }
        }
    }
}

import Foundation

final class ToolExecutor {
    /// Run a shell command (bash) and capture its output (stdout+stderr).
    /// Returns the combined output via a Result.
    static func run(_ command: String,
                    arguments: [String] = [],
                    cwd: URL? = nil,
                    timeout: TimeInterval = 30,
                    completion: @escaping (Result<String, Error>) -> Void) {
        let proc = Process()
        proc.executableURL = URL(fileURLWithPath: command)
        proc.arguments = arguments
        if let cwd = cwd { proc.currentDirectoryURL = cwd }
        let outPipe = Pipe()
        let errPipe = Pipe()
        proc.standardOutput = outPipe
        proc.standardError = errPipe
        do { try proc.run() } catch { completion(.failure(error)); return }
        // Timeout handling
        DispatchQueue.global().asyncAfter(deadline: .now() + timeout) {
            if proc.isRunning { proc.terminate() }
        }
        let outData = outPipe.fileHandleForReading.readDataToEndOfFile()
        let errData = errPipe.fileHandleForReading.readDataToEndOfFile()
        proc.waitUntilExit()
        let outStr = String(decoding: outData, as: UTF8.self)
        let errStr = String(decoding: errData, as: UTF8.self)
        if proc.terminationStatus == 0 {
            completion(.success(outStr + (errStr.isEmpty ? "" : "\n"+errStr)))
        } else {
            let msg = "Exit \(proc.terminationStatus) – \(errStr)"
            completion(.failure(NSError(domain: "Tool", code: Int(proc.terminationStatus), userInfo: [NSLocalizedDescriptionKey: msg])))
        }
    }
}

